package com.anvritai.abhay.service;
import com.anvritai.abhay.domain.*;import com.anvritai.abhay.domain.accounting.*;import com.anvritai.abhay.domain.automation.*;import com.anvritai.abhay.domain.memory.MemoryEvent;import com.anvritai.abhay.domain.sales.Invoice;import com.anvritai.abhay.repository.*;import com.anvritai.abhay.repository.accounting.*;import com.anvritai.abhay.repository.automation.*;import com.anvritai.abhay.repository.memory.*;import com.anvritai.abhay.repository.sales.*;import com.fasterxml.jackson.databind.ObjectMapper;import java.io.*;import java.nio.charset.StandardCharsets;import java.time.Instant;import java.util.*;import java.util.zip.*;import org.springframework.http.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class EnterpriseExportService{
 private static final Set<String> RESOURCES=Set.of("ledgers","vouchers","invoices","memory","automation","settings");private static final Set<String> FORMATS=Set.of("JSON","CSV","EXCEL","PDF");private final CompanyAccessService access;private final CompanyRepository companies;private final LedgerRepository ledgers;private final VoucherRepository vouchers;private final InvoiceRepository invoices;private final MemoryEventRepository memory;private final AutomationRuleRepository rules;private final CompanySettingRepository settings;private final AuditService audit;private final UserRepository users;private final ObjectMapper json;
 public EnterpriseExportService(CompanyAccessService access,CompanyRepository companies,LedgerRepository ledgers,VoucherRepository vouchers,InvoiceRepository invoices,MemoryEventRepository memory,AutomationRuleRepository rules,CompanySettingRepository settings,AuditService audit,UserRepository users,ObjectMapper json){this.access=access;this.companies=companies;this.ledgers=ledgers;this.vouchers=vouchers;this.invoices=invoices;this.memory=memory;this.rules=rules;this.settings=settings;this.audit=audit;this.users=users;this.json=json;}
 @Transactional(readOnly=true) public ResponseEntity<byte[]> export(UUID userId,UUID companyId,String rawResource,String rawFormat){access.requireMembership(companyId,userId);String resource=rawResource.toLowerCase(Locale.ROOT);String format=rawFormat.toUpperCase(Locale.ROOT);if(!RESOURCES.contains(resource)||!FORMATS.contains(format))throw new AccountingRuleException("Unsupported export resource or format.");List<Map<String,Object>> rows=rows(companyId,resource);byte[] body;String extension;MediaType type;switch(format){case "JSON"->{body=write(rows);extension="json";type=MediaType.APPLICATION_JSON;}case "PDF"->{body=pdf(resource,rows);extension="pdf";type=MediaType.APPLICATION_PDF;}case "EXCEL"->{body=csv(rows);extension="xls";type=MediaType.parseMediaType("application/vnd.ms-excel");}default->{body=csv(rows);extension="csv";type=MediaType.parseMediaType("text/csv");}}return ResponseEntity.ok().contentType(type).header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=\""+resource+"-export."+extension+"\"").body(body);}
 @Transactional public ResponseEntity<byte[]> backup(UUID userId,UUID companyId){access.requireRole(companyId,userId,RoleCode.OWNER,RoleCode.ADMIN);Company c=companies.findById(companyId).orElseThrow(()->new NotFoundException("Company not found."));Map<String,Object> snapshot=new LinkedHashMap<>();snapshot.put("schemaVersion",1);snapshot.put("generatedAt",Instant.now());snapshot.put("company",Map.of("id",c.getId(),"legalName",c.getLegalName(),"tradeName",Objects.toString(c.getTradeName(),""),"gstin",Objects.toString(c.getGstin(),""),"stateCode",Objects.toString(c.getStateCode(),"")));for(String resource:RESOURCES)snapshot.put(resource,rows(companyId,resource));byte[] zip=zip(write(snapshot));User actor=users.findById(userId).orElseThrow(()->new NotFoundException("Account not found."));audit.record(c,actor,"COMPANY_BACKUP_EXPORTED","COMPANY",companyId,Map.of("schemaVersion",1));return ResponseEntity.ok().contentType(MediaType.parseMediaType("application/zip")).header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=\"abhay-company-backup.zip\"").body(zip);}
 private List<Map<String,Object>> rows(UUID companyId,String resource){return switch(resource){case "ledgers"->ledgers.findAllByCompanyIdOrderByName(companyId).stream().map(this::ledger).toList();case "vouchers"->vouchers.findAllByCompanyIdOrderByVoucherDateDescVoucherNumberDesc(companyId).stream().map(this::voucher).toList();case "invoices"->invoices.findAllByCompanyIdOrderByInvoiceDateDescInvoiceNumberDesc(companyId).stream().map(this::invoice).toList();case "memory"->memory.findAllByCompanyIdOrderByOccurredAtDesc(companyId).stream().map(this::memory).toList();case "automation"->rules.findAllByCompanyIdOrderByCreatedAtDesc(companyId).stream().map(this::rule).toList();default->settings.findAllByCompanyIdOrderByCategoryAscSettingKeyAsc(companyId).stream().map(this::setting).toList();};}
 private Map<String,Object> ledger(Ledger x){return ordered("id",x.getId(),"name",x.getName(),"code",x.getCode(),"type",x.getLedgerType(),"openingDebit",x.getOpeningDebit(),"openingCredit",x.getOpeningCredit());}private Map<String,Object> voucher(Voucher x){return ordered("id",x.getId(),"number",x.getVoucherNumber(),"date",x.getVoucherDate(),"status",x.getStatus(),"narration",Objects.toString(x.getNarration(),""));}private Map<String,Object> invoice(Invoice x){return ordered("id",x.getId(),"number",x.getInvoiceNumber(),"date",x.getInvoiceDate(),"type",x.getInvoiceType(),"status",x.getStatus(),"subtotal",x.getSubtotal(),"total",x.getTotal());}private Map<String,Object> memory(MemoryEvent x){return ordered("id",x.getId(),"type",x.getMemoryType(),"event",x.getEventType(),"subject",Objects.toString(x.getSubjectKey(),""),"occurredAt",x.getOccurredAt());}private Map<String,Object> rule(AutomationRule x){return ordered("id",x.getId(),"name",x.getName(),"type",x.getRuleType(),"schedule",x.getScheduleType(),"active",x.isActive());}private Map<String,Object> setting(CompanySetting x){return ordered("category",x.getCategory(),"key",x.getSettingKey(),"value",x.getSettingValue(),"type",x.getValueType());}
 private Map<String,Object> ordered(Object... values){Map<String,Object> m=new LinkedHashMap<>();for(int i=0;i<values.length;i+=2)m.put(values[i].toString(),values[i+1]);return m;}private byte[] write(Object value){try{return json.writerWithDefaultPrettyPrinter().writeValueAsBytes(value);}catch(Exception e){throw new IllegalStateException("Export could not be generated.",e);}}
 private byte[] csv(List<Map<String,Object>> rows){if(rows.isEmpty())return "record_id\n".getBytes(StandardCharsets.UTF_8);List<String> headers=new ArrayList<>(rows.getFirst().keySet());StringBuilder out=new StringBuilder(String.join(",",headers)).append('\n');for(Map<String,Object> row:rows){for(int i=0;i<headers.size();i++){if(i>0)out.append(',');String v=Objects.toString(row.get(headers.get(i)),"").replace("\"","\"\"");out.append('\"').append(v).append('\"');}out.append('\n');}return out.toString().getBytes(StandardCharsets.UTF_8);}
 private byte[] pdf(String title,List<Map<String,Object>> rows){String text=("ABHAY "+title.toUpperCase(Locale.ROOT)+" EXPORT - "+rows.size()+" record(s)").replace("(","[").replace(")","]");String stream="BT /F1 12 Tf 50 760 Td ("+text+") Tj ET";List<String> objects=List.of("<< /Type /Catalog /Pages 2 0 R >>","<< /Type /Pages /Kids [3 0 R] /Count 1 >>","<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] /Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>","<< /Length "+stream.length()+" >>\nstream\n"+stream+"\nendstream","<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>");StringBuilder p=new StringBuilder("%PDF-1.4\n");List<Integer> offsets=new ArrayList<>();for(int i=0;i<objects.size();i++){offsets.add(p.length());p.append(i+1).append(" 0 obj\n").append(objects.get(i)).append("\nendobj\n");}int xref=p.length();p.append("xref\n0 ").append(objects.size()+1).append("\n0000000000 65535 f \n");for(int offset:offsets)p.append(String.format(Locale.ROOT,"%010d 00000 n \n",offset));p.append("trailer << /Size ").append(objects.size()+1).append(" /Root 1 0 R >>\nstartxref\n").append(xref).append("\n%%EOF");return p.toString().getBytes(StandardCharsets.US_ASCII);}
 private byte[] zip(byte[] snapshot){try{ByteArrayOutputStream out=new ByteArrayOutputStream();try(ZipOutputStream zip=new ZipOutputStream(out)){zip.putNextEntry(new ZipEntry("snapshot.json"));zip.write(snapshot);zip.closeEntry();zip.putNextEntry(new ZipEntry("README.txt"));zip.write("ABHAY company snapshot. Restore requires validated administrative import.".getBytes(StandardCharsets.UTF_8));zip.closeEntry();}return out.toByteArray();}catch(IOException e){throw new IllegalStateException("Backup could not be generated.",e);}}
}
